26984	int ds4_sample_logits(const float *logits, int n_vocab, float temperature,
26985	                      int top_k, float top_p, float min_p, uint64_t *rng) {
26986	    if (!logits || n_vocab <= 0) return 0;
26987	    return sample_top_p_min_p(logits, (uint32_t)n_vocab, temperature, top_k, top_p, min_p, rng);
26988	}
26989	
26990	int ds4_session_sample(ds4_session *s, float temperature, int top_k, float top_p, float min_p, uint64_t *rng) {
26991	    return sample_top_p_min_p(s->logits, DS4_N_VOCAB, temperature, top_k, top_p, min_p, rng);
26992	}
26993	
26994	int ds4_session_top_logprobs(ds4_session *s, ds4_token_score *out, int k) {
26995	    if (!s || !out || k <= 0) return 0;
26996	    if (k > (int)DS4_N_VOCAB) k = (int)DS4_N_VOCAB;
26997	    for (int i = 0; i < k; i++) {
26998	        out[i].id = -1;
26999	        out[i].logit = DS4_NEG_INF;
27000	        out[i].logprob = DS4_NEG_INF;
27001	    }
27002	
27003	    float max_logit = DS4_NEG_INF;
27004	    for (uint32_t i = 0; i < DS4_N_VOCAB; i++) {
27005	        const float v = s->logits[i];
27006	        if (!isfinite(v)) continue;
27007	        if (v > max_logit) max_logit = v;
27008	        for (int j = 0; j < k; j++) {
27009	            if (out[j].id < 0 || v > out[j].logit) {
27010	                for (int l = k - 1; l > j; l--) out[l] = out[l - 1];
27011	                out[j].id = (int)i;
27012	                out[j].logit = v;
27013	                break;
27014	            }
27015	        }
27016	    }
27017	    if (!isfinite(max_logit)) return 0;
27018	
27019	    double sum = 0.0;
27020	    for (uint32_t i = 0; i < DS4_N_VOCAB; i++) {
27021	        const float v = s->logits[i];
27022	        if (isfinite(v)) sum += exp((double)v - (double)max_logit);
27023	    }
27024	    const double logsum = (double)max_logit + log(sum);
27025	    for (int i = 0; i < k && out[i].id >= 0; i++) {
27026	        out[i].logprob = isfinite(out[i].logit) ? (float)((double)out[i].logit - logsum) : DS4_NEG_INF;
27027	    }
27028	    return k;
27029	}
27030	
27031	int ds4_session_token_logprob(ds4_session *s, int token, ds4_token_score *out) {
27032	    if (!s || !out || token < 0 || token >= (int)DS4_N_VOCAB) return 0;
27033	
27034	    float max_logit = DS4_NEG_INF;
27035	    for (uint32_t i = 0; i < DS4_N_VOCAB; i++) {
27036	        const float v = s->logits[i];
27037	        if (isfinite(v) && v > max_logit) max_logit = v;
27038	    }
27039	    if (!isfinite(max_logit)) return 0;
27040	
27041	    double sum = 0.0;
27042	    for (uint32_t i = 0; i < DS4_N_VOCAB; i++) {
27043	        const float v = s->logits[i];
27044	        if (isfinite(v)) sum += exp((double)v - (double)max_logit);
27045	    }
27046	    const double logsum = (double)max_logit + log(sum);
27047	    out->id = token;
27048	    out->logit = s->logits[token];
27049	    out->logprob = isfinite(out->logit) ? (float)((double)out->logit - logsum) : DS4_NEG_INF;
27050	    return 1;
27051	}
27052	
27053	int ds4_session_copy_logits(ds4_session *s, float *out, int cap) {
27054	    if (!s || !out || cap < (int)DS4_N_VOCAB) return 0;
27055	    memcpy(out, s->logits, (size_t)DS4_N_VOCAB * sizeof(out[0]));
27056	    return (int)DS4_N_VOCAB;
27057	}
27058	
27059	int ds4_session_set_logits(ds4_session *s, const float *logits, int n) {
27060	    if (!s || !logits || n != (int)DS4_N_VOCAB) return 1;
27061	    memcpy(s->logits, logits, (size_t)DS4_N_VOCAB * sizeof(s->logits[0]));
27062	    return 0;
27063	}
27064	
27065	static int ds4_session_eval_internal(ds4_session *s, int token, bool probe_mtp,
27066	                                     char *err, size_t errlen) {
27067	    if (!s) return 1;
27068	    if (s->distributed) {
27069	        if (!s->checkpoint_valid) {
27070	            if (errlen) snprintf(err, errlen, "distributed decode requires a valid checkpoint");
27071	            return 1;
27072	        }
27073	        (void)probe_mtp;
27074	        return ds4_dist_session_eval(s->distributed,
27075	                                     s,
27076	                                     &s->checkpoint,
