546	    size_t i = 0;
547	    while (i < n) {
548	        unsigned char c = (unsigned char)s[i++];
549	        if (c < 0x80) continue;
550	        int need = 0;
551	        if (c >= 0xc2 && c <= 0xdf) need = 1;
552	        else if (c >= 0xe0 && c <= 0xef) need = 2;
553	        else if (c >= 0xf0 && c <= 0xf4) need = 3;
554	        else return false;
555	        if (i + (size_t)need > n) return false;
556	        unsigned char c1 = (unsigned char)s[i];
557	        if (c == 0xe0 && c1 < 0xa0) return false;
558	        if (c == 0xed && c1 >= 0xa0) return false;
559	        if (c == 0xf0 && c1 < 0x90) return false;
560	        if (c == 0xf4 && c1 >= 0x90) return false;
561	        for (int j = 0; j < need; j++) {
562	            unsigned char cc = (unsigned char)s[i + (size_t)j];
563	            if ((cc & 0xc0) != 0x80) return false;
564	        }

